// Tests for row-tiled bilateral filter via FRF. Verifies bit-exact (within
// float drift) parity with the single-pass image-bilateral.ts and that
// tile-count / concurrency variations don't change the output.

import { describe, it, expect } from 'vitest';
import { bilateralFilter } from '../src/image-bilateral';
import { bilateralFilterFRF } from '../src/image-bilateral-frf';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff - 0.5;
  };
}

function naturalish64(seed: number): Float32Array {
  const w = 64,
    h = 64;
  const out = new Float32Array(w * h);
  const rand = lcg(seed);
  const cx = w / 2,
    cy = h / 2,
    scale = (Math.min(w, h) ** 2) / 16;
  for (let y = 0; y < h; y++)
    for (let x = 0; x < w; x++) {
      const dx = x - cx,
        dy = y - cy;
      const radial = Math.exp(-(dx * dx + dy * dy) / scale);
      const ripple = 0.15 * Math.sin(x / 5) * Math.cos(y / 4);
      const noise = 0.05 * rand();
      let v = radial + ripple + noise;
      if (v < 0) v = 0;
      if (v > 1) v = 1;
      out[y * w + x] = v;
    }
  return out;
}

function maxAbsDelta(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let m = 0;
  for (let i = 0; i < a.length; i++) {
    const d = Math.abs(a[i] - b[i]);
    if (d > m) m = d;
  }
  return m;
}

function rmse(a: Float32Array, b: Float32Array): number {
  if (a.length !== b.length) {
    throw new Error(`length mismatch ${a.length} vs ${b.length}`);
  }
  let s = 0;
  for (let i = 0; i < a.length; i++) {
    const d = a[i] - b[i];
    s += d * d;
  }
  return Math.sqrt(s / a.length);
}

describe('bilateralFilterFRF', () => {
  it('matches single-tile bilateralFilter on a 64x64 plane within 1e-5', async () => {
    const plane = naturalish64(0xc0ffee);
    const ref = bilateralFilter({
      plane,
      width: 64,
      height: 64,
      sigmaSpatial: 2,
      sigmaIntensity: 0.05,
    });
    const got = await bilateralFilterFRF({
      plane,
      width: 64,
      height: 64,
      sigmaSpatial: 2,
      sigmaIntensity: 0.05,
      tiles: 4,
    });
    expect(got.length).toBe(ref.length);
    expect(maxAbsDelta(ref, got)).toBeLessThan(1e-5);
  });

  it('produces consistent output across tiles in {1,2,4,8}', async () => {
    const plane = naturalish64(0xbadf00d);
    const w = 64,
      h = 64,
      sigmaSpatial = 2,
      sigmaIntensity = 0.05;
    const ref = bilateralFilter({
      plane,
      width: w,
      height: h,
      sigmaSpatial,
      sigmaIntensity,
    });
    for (const tiles of [1, 2, 4, 8]) {
      const got = await bilateralFilterFRF({
        plane,
        width: w,
        height: h,
        sigmaSpatial,
        sigmaIntensity,
        tiles,
      });
      expect(got.length).toBe(ref.length);
      expect(rmse(ref, got)).toBeLessThan(1e-5);
    }
  });

  it('throws RangeError on bad inputs', async () => {
    const plane = new Float32Array(64 * 64);

    // bad width
    await expect(
      bilateralFilterFRF({ plane, width: 0, height: 64 }),
    ).rejects.toBeInstanceOf(RangeError);

    // bad height
    await expect(
      bilateralFilterFRF({ plane, width: 64, height: 0 }),
    ).rejects.toBeInstanceOf(RangeError);

    // length mismatch
    await expect(
      bilateralFilterFRF({
        plane: new Float32Array(10),
        width: 64,
        height: 64,
      }),
    ).rejects.toBeInstanceOf(RangeError);

    // bad sigmaSpatial
    await expect(
      bilateralFilterFRF({
        plane,
        width: 64,
        height: 64,
        sigmaSpatial: 0,
      }),
    ).rejects.toBeInstanceOf(RangeError);

    // bad sigmaIntensity
    await expect(
      bilateralFilterFRF({
        plane,
        width: 64,
        height: 64,
        sigmaIntensity: -1,
      }),
    ).rejects.toBeInstanceOf(RangeError);

    // tiles = 0
    await expect(
      bilateralFilterFRF({ plane, width: 64, height: 64, tiles: 0 }),
    ).rejects.toBeInstanceOf(RangeError);

    // tiles > height (50-row plane, ask for 100 tiles)
    const plane50 = new Float32Array(64 * 50);
    await expect(
      bilateralFilterFRF({
        plane: plane50,
        width: 64,
        height: 50,
        tiles: 100,
      }),
    ).rejects.toBeInstanceOf(RangeError);

    // bad concurrency
    await expect(
      bilateralFilterFRF({
        plane,
        width: 64,
        height: 64,
        concurrency: 0,
      }),
    ).rejects.toBeInstanceOf(RangeError);
  });

  it('returns a fresh Float32Array, not a view into the input', async () => {
    const plane = naturalish64(0x1234);
    const got = await bilateralFilterFRF({
      plane,
      width: 64,
      height: 64,
      tiles: 4,
    });
    expect(got).toBeInstanceOf(Float32Array);
    expect(got.buffer).not.toBe(plane.buffer);
    // Mutating output must not change input.
    const before = plane[0];
    got[0] = 999;
    expect(plane[0]).toBe(before);
  });

  it('uses default tiles = min(8, height) when omitted', async () => {
    // 4-row plane → default tiles must collapse to 4 (not 8) and run cleanly.
    const w = 16,
      h = 4;
    const plane = new Float32Array(w * h);
    const rand = lcg(42);
    for (let i = 0; i < plane.length; i++) plane[i] = 0.5 + 0.3 * rand();
    const ref = bilateralFilter({
      plane,
      width: w,
      height: h,
      sigmaSpatial: 1,
      sigmaIntensity: 0.05,
    });
    const got = await bilateralFilterFRF({
      plane,
      width: w,
      height: h,
      sigmaSpatial: 1,
      sigmaIntensity: 0.05,
      // tiles omitted → min(8, 4) = 4
    });
    expect(got.length).toBe(ref.length);
    expect(maxAbsDelta(ref, got)).toBeLessThan(1e-5);
  });

  it('respects concurrency cap without breaking correctness', async () => {
    const plane = naturalish64(0xfeedface);
    const ref = bilateralFilter({
      plane,
      width: 64,
      height: 64,
      sigmaSpatial: 2,
      sigmaIntensity: 0.05,
    });
    const got = await bilateralFilterFRF({
      plane,
      width: 64,
      height: 64,
      sigmaSpatial: 2,
      sigmaIntensity: 0.05,
      tiles: 8,
      concurrency: 2,
    });
    expect(got.length).toBe(ref.length);
    expect(maxAbsDelta(ref, got)).toBeLessThan(1e-5);
  });
});
